        if (reset)
            count <= 2'b00;
        else if (count == 2'b11)
            count <= 2'b00;
        else
            count <= count + 1;
    end
  always @(*) begin
    if (1'b0) begin
      if (reset) begin
        count <= 2'b11;
      end else if (count == 2'b00) begin
        count <= 2'b11;
      end
    end
  end

endmodule

